import{_ as r,c as e,o as t,aN as i}from"./chunks/framework.BRm39z_l.js";const A=JSON.parse('{"title":"Java List","description":"","frontmatter":{},"headers":[],"relativePath":"java/02.Java集合/02.Java List.md","filePath":"java/02.Java集合/02.Java List.md"}'),o={name:"java/02.Java集合/02.Java List.md"};function s(d,a,l,c,n,y){return t(),e("div",null,a[0]||(a[0]=[i('<h1 id="java-list" tabindex="-1">Java List <a class="header-anchor" href="#java-list" aria-label="Permalink to &quot;Java List&quot;">​</a></h1><h2 id="arraylist-和-array-数组-的区别-加灵活" tabindex="-1">ArrayList 和 Array（数组）的区别？加灵活： <a class="header-anchor" href="#arraylist-和-array-数组-的区别-加灵活" aria-label="Permalink to &quot;ArrayList 和 Array（数组）的区别？加灵活：&quot;">​</a></h2><ul><li><code>ArrayList</code>会根据实际存储的元素动态地扩容或缩容，而 <code>Array</code> 被创建之后就不能改变它的长度了。</li><li><code>ArrayList</code> 允许你使用泛型来确保类型安全，<code>Array</code> 则不可以。</li><li><code>ArrayList</code> 中只能存储对象。对于基本类型数据，需要使用其对应的包装类（如 Integer、Double 等）。<code>Array</code> 可以直接存储基本类型数据，也可以存储对象。</li><li><code>ArrayList</code> 支持插入、删除、遍历等常见操作，并且提供了丰富的 API 操作方法，比如 <code>add()</code>、<code>remove()</code>等。<code>Array</code> 只是一个固定长度的数组，只能按照下标访问其中的元素，不具备动态添加、删除元素的能力。</li><li><code>ArrayList</code>创建时不需要指定大小，而<code>Array</code>创建时必须指定大小</li></ul><h2 id="arraylist-和-linkedlist-有什么区别" tabindex="-1">ArrayList 和 LinkedList 有什么区别？ <a class="header-anchor" href="#arraylist-和-linkedlist-有什么区别" aria-label="Permalink to &quot;ArrayList 和 LinkedList 有什么区别？&quot;">​</a></h2><p>ArrayList 是基于数组实现的， LinkedList 是基于链表实现的</p><p>多数情况下， ArrayList 更利于查找， LinkedList 更利于增删</p><h2 id="arraylist-的扩容机制了解吗" tabindex="-1">ArrayList 的扩容机制了解吗？ <a class="header-anchor" href="#arraylist-的扩容机制了解吗" aria-label="Permalink to &quot;ArrayList 的扩容机制了解吗？&quot;">​</a></h2><p>当往 ArrayList 中添加元素时，会先检查是否需要扩容，如果当前容量+1 超过数组⻓度，就会进⾏扩容。</p><p>扩容后的新数组⻓度是原来的 1.5 倍，然后再把原数组的值拷⻉到新数组中</p>',9)]))}const _=r(o,[["render",s]]);export{A as __pageData,_ as default};
